sql:
SELECT DISTINCT manufacturer
FROM components
WHERE bolt_size_unc IS NOT NULL;

SELECT manufacturer, COUNT(DISTINCT part_number) AS unique_part_numbers
FROM components
GROUP BY manufacturer;

external_knowledge:
Hefty components refer to those weighing over 5.0 kg;
"Details" include the material name, supplier name, component status, and notes;
"Sorted by the date they were brought in, favoring the more recent ones" means the results are ordered by the date added in descending order.

sql:
SELECT SUM(components.wn_kg * inventory.quantity) AS TotalWeight
FROM components
JOIN inventory ON components.component_id = inventory.component_id;

SELECT part_number
FROM components
WHERE status = 'obsolete' AND wn_kg > (SELECT AVG(wn_kg) FROM components);

SELECT SUM(quantity) AS Total_Quantity
FROM inventory
WHERE component_id = 'SpecificComponentID';

SELECT COUNT(*) AS Components_Ordered, SUM(components.wn_kg) AS Total_Weight
FROM components
JOIN orders ON components.component_id = orders.component_id;
